extern "C" void pointnet2RegisterAllOpResources();

void RunAclnn(const at::Tensor& stream_tensor, const char* op_name, WorkspaceFn workspace_fn, LaunchFn launch_fn)
{
    EnsurePointnet2ResourcesRegistered();
    uint64_t workspace_size = 0;
    aclOpExecutor* executor = nullptr;
    CheckStatus(workspace_fn(&workspace_size, &executor), (std::string(op_name) + " GetWorkspaceSize").c_str());
    at::Tensor workspace;
    void* workspace_ptr = nullptr;
    if (workspace_size > 0) {
        workspace = at::empty({static_cast<int64_t>(workspace_size)}, stream_tensor.options().dtype(at::kByte));
        workspace_ptr = workspace.data_ptr();
    }
    aclrtStream stream = c10_npu::getCurrentNPUStream(stream_tensor.device().index()).stream();
    aclnnStatus launch_status = launch_fn(workspace_ptr, workspace_size, executor, stream);
    aclnnStatus destroy_status = aclDestroyAclOpExecutor(executor);
    CheckStatus(launch_status, (std::string(op_name) + " launch").c_str());
    CheckStatus(destroy_status, (std::string(op_name) + " destroy executor").c_str());
}

aclTensor* ConvertType(const at::Tensor& tensor)
{
    const aclDataType data_type = ToAclDataType(tensor.scalar_type());
    if (data_type == ACL_DT_UNDEFINED) {
        return nullptr;
    }
    const auto sizes = tensor.sizes();
    const auto strides = tensor.strides();
    std::vector<int64_t> shape(sizes.begin(), sizes.end());
    std::vector<int64_t> stride_vec(strides.begin(), strides.end());
    int64_t storage_len = tensor.numel();
    return aclCreateTensor(shape.data(), shape.size(), data_type, stride_vec.data(), tensor.storage_offset(), ACL_FORMAT_ND, &storage_len, 1, tensor.data_ptr());
}

void Release(aclTensor* tensor)
{
    if (tensor != nullptr) {
        aclDestroyTensor(tensor);
    }
}

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext* context)
{
    const gert::Shape* points = context->GetInputShape(0);
    const gert::Shape* idx = context->GetInputShape(1);
    gert::Shape* y = context->GetOutputShape(0);
    y->SetDimNum(0);
    y->AppendDim(points->GetDim(0));
    y->AppendDim(points->GetDim(1));
    y->AppendDim(idx->GetDim(1));
    return GRAPH_SUCCESS;
}
static ge::graphStatus InferDataType(gert::InferDataTypeContext *context)
{
    const auto inputDataType = context->GetInputDataType(0);
    context->SetOutputDataType(0, inputDataType);
    return ge::GRAPH_SUCCESS;
}
}

namespace ops {
class Pointnet2GatherPoints : public OpDef {
public:
    explicit Pointnet2GatherPoints(const char* name) : OpDef(name)
    {
        this->Input("points").ParamType(REQUIRED).DataType({ge::DT_FLOAT16, ge::DT_FLOAT}).Format({ge::FORMAT_ND, ge::FORMAT_ND}).UnknownShapeFormat({ge::FORMAT_ND, ge::FORMAT_ND});
        this->Input("idx").ParamType(REQUIRED).DataType({ge::DT_INT32, ge::DT_INT32}).Format({ge::FORMAT_ND, ge::FORMAT_ND}).UnknownShapeFormat({ge::FORMAT_ND, ge::FORMAT_ND});
        this->Output("out").ParamType(REQUIRED).DataType({ge::DT_FLOAT16, ge::DT_FLOAT}).Format({ge::FORMAT_ND, ge::FORMAT_ND}).UnknownShapeFormat({ge::FORMAT_ND, ge::FORMAT_ND});
        this->SetInferShape(ge::InferShape).SetInferDataType(ge::InferDataType);
        this->AICore().SetTiling(optiling::TilingFunc);
        this->AICore().AddConfig("ascend910b");
    }
};
OP_ADD(Pointnet2GatherPoints);
}

#include "kernel_operator.h"
using namespace AscendC;
extern "C" __global__ __aicore__ void pointnet2_gather_points(GM_ADDR points, GM_ADDR idx, GM_ADDR out, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(t, tiling);
    for (uint32_t bb = 0; bb < t.b; ++bb) {
        for (uint32_t cc = 0; cc < t.c; ++cc) {
            for (uint32_t mm = 0; mm < t.m; ++mm) {
                int32_t src = ((__gm__ int32_t*)idx)[bb * t.m + mm];
                ((__gm__ float*)out)[bb * t.c * t.m + cc * t.m + mm] = ((__gm__ float*)points)[bb * t.c * t.n + cc * t.n + src];
            }
        }
    }
}
